sections.code:
MobileScanner(
  controller: MobileScannerController(
    detectionSpeed: DetectionSpeed.normal,
    facing: CameraFacing.back,
    formats: const [BarcodeFormat.qrCode, BarcodeFormat.ean13],
  ),
  onDetect: (capture) {
    for (final b in capture.barcodes) handle(b.rawValue);
  },
)
